using namespace std;

bool binarySearch(vector<int>& temp, int x)
{
     for(int x:temp)
     {
          //cout << x << " ";
     }
     cout << endl;
     int n = temp.size();
     int s = 0;
     int e = n-1;
     while(s <= e)
     {
          int mid = s+(e-s)/2;
          //cout << "temp[mid]: " << temp[mid] << endl;
          if(temp[mid] == x)
               return true;
          else if(temp[mid] > x)
               e = mid-1;
          else
               s = mid+1;
     }    
     return false;
}

int reverse(int n)
{
     int rev = 0;
     while(n > 0)
     {
          int d = n%10;
          rev = rev*10+d;
          n /= 10;
     }
     return rev;
}

int minMirrorPairDistance(vector<int>& nums) 
{
     /* // Not optimize buts works
        int minIdx = INT_MAX;
        bool found = false;
        for(int i=0;i<nums.size();i++)
        {
        for(int j=i+1;j<nums.size();j++)
        {
        int revNum = reverse(nums[i]);        
        if(nums[j] == revNum)
        {
        found = true;
        int si = abs(i-j);
        if(minIdx > si)     
        minIdx = si;     
        }
        }
        }
        if(found)
        return minIdx;
        return -1;
      */
     //cout << "Size: " << nums.size() << endl;
     unordered_map<int, int> mp; 
     int minIdx = INT_MAX;
     for(int i = 0; i < nums.size(); i++)
     {
          if(mp.count(nums[i]))
          {
               minIdx = min(minIdx, i - mp[nums[i]]);
          }
          int rev = reverse(nums[i]);
          mp[rev] = i;
     } 
     if(minIdx != INT_MAX)
          return minIdx;
     return -1;
}
